import * as t from "io-ts";
import { intentTypes } from "./intentType";
import { BaseStakeIntent } from "./baseStakeIntent";

/**
 * @title Baby CreateBtcDelegation Intent
 *
 * @param {string} createBtcDelegationBytes - MsgCreateBTCDelegation protobuf bytes encoded as hex
 */
export const BabyCreateBtcDelegationIntent = t.intersection([
  BaseStakeIntent,
  t.type({
    intentType: intentTypes.createBtcDelegation,
    createBtcDelegationBytes: t.string,
  }),
]);

export type BabyCreateBtcDelegationIntent = t.TypeOf<
  typeof BabyCreateBtcDelegationIntent
>;
